"use strict";(self.webpackChunkheidelbergman_site=self.webpackChunkheidelbergman_site||[]).push([[673],{7994:e=>{e.exports=JSON.parse('[{"id":"/2026/05/12/_streckenchecks","metadata":{"permalink":"/blog/2026/05/12/_streckenchecks","source":"@site/blog/2026-05-12_streckenchecks.md","title":"Streckenchecks","description":"Staffel","date":"2026-05-12T00:00:00.000Z","formattedDate":"12. Mai 2026","tags":[],"hasTruncateMarker":false,"authors":[{"name":"Orga Team","title":"Heidelberg-Triathlon Orga Team","imageURL":"https://www.heidelberg-triathlon.de/img/logo/HDtri_round_mini.png","key":"orga"}],"frontMatter":{"title":"Streckenchecks","authors":["orga"]},"unlisted":false,"nextItem":{"title":"Wir sind ausgebucht!","permalink":"/blog/2026/01/21/ausgebucht2"}},"content":"![Staffel](/blog/2026_streckenchecks.png)\\n\\nDie Streckenchecks sind eine tolle Gelegenheit, die Strecken des Heidelberg Triathlons kennenzulernen und sich optimal auf den Wettkampf vorzubereiten. Wir laden alle Teilnehmenden herzlich ein, an den Streckenchecks teilzunehmen.\\n\\n**Schwimmen im Neckar:**\\n- **21. Juni**: Testschwimmen im Neckar @Neckarwiese, Theodor-Heuss-Br\xfccke, 16:00 Uhr (Uferstra\xdfe 6, 69120 Heidelberg).<br/>\\n*Bitte* meldet euch f\xfcr das Testschwimmen unverbindlich an, damit wir besser planen k\xf6nnen. Ihr k\xf6nnt euch \xfcber den folgenden Link anmelden: [Anmeldung Testschwimmen](https://forms.gle/Tx48annmW2dViHQEA)\\n\\n\\n**Radstreckenchecks:**\\n- **20. Mai**: Radstreckencheck X WattsUpGirls (women only) @ OK Kool Altstad Heidelberg, 18:00 Uhr \\n- **30. Main**: Radstreckencheck X Velociraptors @ Uferstra\xdfe 4, 15:00 Uhr\\n- **07. Juli**: Radstreckencheck X ACE @ Uferstra\xdfe 4, 18:00 Uhr\\n\\n**Laufstreckenchecks:**\\n- **11. Mai**: Laufstreckencheck X ACE @ Uferstr. 4, 18:00 Uhr\\n- **02. Juli**: Laufstreckencheck X cheaper than therapy run club  @ Uferstra\xdfe 4, 18:30 Uhr\\n\\nDie Streckenchecks sind kostenlos und bieten eine gro\xdfartige Gelegenheit, sich mit der Strecke vertraut zu machen, Tipps von erfahrenen Athlet\'innen zu erhalten und die Atmosph\xe4re des Heidelberg Triathlons zu erleben.\\nDie Teilnahme an den Streckenchecks ist f\xfcr alle Teilnehmenden des Heidelberg Triathlons offen, unabh\xe4ngig von der Distanz, die sie w\xe4hlen. Wir freuen uns auf zahlreiche Teilnehmer\'innen und eine tolle gemeinsame Vorbereitung auf den Wettkampf!\\n\\nWir freuen uns auf eure Teilnahme und w\xfcnschen euch viel Spa\xdf bei den Streckenchecks!"},{"id":"/2026/01/21/ausgebucht2","metadata":{"permalink":"/blog/2026/01/21/ausgebucht2","source":"@site/blog/2026-01-21-ausgebucht2.md","title":"Wir sind ausgebucht!","description":"Bild","date":"2026-01-21T00:00:00.000Z","formattedDate":"21. Januar 2026","tags":[],"hasTruncateMarker":false,"authors":[{"name":"Orga Team","title":"Heidelberg-Triathlon Orga Team","imageURL":"https://www.heidelberg-triathlon.de/img/logo/HDtri_round_mini.png","key":"orga"}],"frontMatter":{"title":"Wir sind ausgebucht!","authors":["orga"]},"unlisted":false,"prevItem":{"title":"Streckenchecks","permalink":"/blog/2026/05/12/_streckenchecks"},"nextItem":{"title":"Einzel-Startpla\u0308tze ausgebucht!","permalink":"/blog/2026/01/11/ausgebucht"}},"content":"![Bild](/blog/2026_01_21.png)\\n\\nWahnsinn! Ihr seid ja der Hammer!!! \ud83e\udd2f\\n\\nIn den letzten Tagen sind nun auch die letzten Staffelpla\u0308tze im Rekordtempo verkauft worden. \ud83d\udcc8\\nAusgebucht in nichtmal 3 Wochen, davon haben wir vor 2 Jahren noch getra\u0308umt. \ud83d\udcad\u2b50\\n\\nDanke fu\u0308r euer Vertrauen und dass ihr auch 2026 wieder genauso viel Bock auf den Heidelberg Triathlon habt wie wir. \ud83d\ude80\ud83d\udd25\\n\\nFu\u0308r alle, die es dieses Mal nicht geschafft haben einen Startplatz zu ergattern:\\nAus eigener Erfahrung ko\u0308nnen wir sagen: Helfen macht mindestens/fast genauso viel Spa\xdf wie Starten! \ud83d\ude4c\ud83c\udffc\\n\\nLiebe Gru\u0308\xdfe, euer Orga Team \ud83e\udef6\ud83c\udffc\\n\\n\ud83d\ude80 Race Day: 26.07.2026 \ud83d\ude80"},{"id":"/2026/01/11/ausgebucht","metadata":{"permalink":"/blog/2026/01/11/ausgebucht","source":"@site/blog/2026-01-11-ausgebucht.md","title":"Einzel-Startpla\u0308tze ausgebucht!","description":"Bild","date":"2026-01-11T00:00:00.000Z","formattedDate":"11. Januar 2026","tags":[],"hasTruncateMarker":false,"authors":[{"name":"Orga Team","title":"Heidelberg-Triathlon Orga Team","imageURL":"https://www.heidelberg-triathlon.de/img/logo/HDtri_round_mini.png","key":"orga"}],"frontMatter":{"title":"Einzel-Startpla\u0308tze ausgebucht!","authors":["orga"]},"unlisted":false,"prevItem":{"title":"Wir sind ausgebucht!","permalink":"/blog/2026/01/21/ausgebucht2"},"nextItem":{"title":"A\u0117ra wird Titelsponsor!","permalink":"/blog/2026/01/01/namessponsor"}},"content":"![Bild](/blog/2026_01_11.webp)\\n\\n\\nWOW! Dieses Jahr musstet ihr richtig schnell sein bei der Anmeldung \ud83e\udd2f\\n\\nWir freuen uns riesig, dass wir schon jetzt wieder alle Einzel-Startpla\u0308tze vergeben konnten!\\n\\nWenn ihr auch am 26. Juli dabei sein wollt: Es gibt noch Staffel-Startpla\u0308tze \ud83c\udfca\u200d\u2642\ufe0f\ud83d\udeb4\u200d\u2642\ufe0f\ud83c\udfc3\u200d\u2642\ufe0f\\nSchnappt euch Friends & Family und geht als Team an den Start \ud83e\udef6\\n\\nFreut euch alle auf ein sportliches Spektakel in Heidelberg \ud83d\ude80\\n\\n#heidelbergtriathlonbyaera #heidelbergtriathlon #swimbikerun #heidelberg #teamrelay"}]')}}]);